// Accept only incoming emails with subject "quotation" and send a form link.
const N8N_PUBLIC_BASE_URL = 'https://n8n.amprosystem.com';
const item = $input.first().json;
const subject = String(item.subject || '').trim().toLowerCase();
const fromRaw = item.from?.value?.[0]?.address || item.from?.text || item.from || item.sender || '';
const fromName = item.from?.value?.[0]?.name || '';
const senderEmail = String(fromRaw).match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i)?.[0] || String(fromRaw).trim();
if (subject !== 'quotation' || !senderEmail) {
  return [{ json: { route: 'ignore', reason: subject !== 'quotation' ? 'subject_not_quotation' : 'missing_sender', subject, senderEmail } }];
}
const formUrl = N8N_PUBLIC_BASE_URL.replace(/\/$/, '') + '/form/email-quotation-request?sender_email=' + encodeURIComponent(senderEmail);
return [{ json: { route: 'send_form_link', senderEmail, fromName, formUrl } }];

// Map n8n form fields + uploaded files into the shared core quotation sub-workflow input.
const BACKEND_API_URL = process.env.BACKEND_API_URL || 'http://172.17.0.1:3001';
const TENANT_SLUG = process.env.RAGM_TENANT_SLUG || 'acme';
const LOGIN_EMAIL = process.env.RAGM_LOGIN_EMAIL || 'admin@acme.com';
const LOGIN_PASSWORD = process.env.RAGM_LOGIN_PASSWORD || 'admin123';
const CALLBACK_ROUTER_URL = process.env.CALLBACK_ROUTER_URL || 'http://172.17.0.1:5678/webhook/pipeline-callback-router';

const input = $input.first();
const data = input.json || {};
const binary = input.binary || {};
function clean(v) { return String(v ?? '').trim(); }
function pickBinary(name, fallbackPattern) {
  if (binary[name]) return { key: name, value: binary[name] };
  const key = Object.keys(binary).find(k => k.toLowerCase().includes(name.toLowerCase()) || (fallbackPattern && fallbackPattern.test(k)));
  return key ? { key, value: binary[key] } : null;
}
async function inlineBinary(picked) {
  const b = picked.value;
  const buf = await this.helpers.getBinaryDataBuffer(0, picked.key);
  return {
    ...b,
    data: buf.toString('base64'),
  };
}
function serviceValue(v) {
  const s = clean(v).toLowerCase();
  if (s === '1' || s.includes('supply only')) return 1;
  if (s === '3' || s.includes('commission')) return 3;
  return 2;
}
const senderEmail = clean(data.sender_email || data.email);
const boqPicked = pickBinary('boq_file', /boq/i);
const specPicked = pickBinary('spec_file', /spec/i);
if (!senderEmail) throw new Error('Missing sender_email hidden field');
if (!boqPicked) throw new Error('Missing BOQ file upload');
if (!specPicked) throw new Error('Missing specification file upload');
const boq = await inlineBinary.call(this, boqPicked);
const spec = await inlineBinary.call(this, specPicked);
const boqName = boq.fileName || 'boq.xlsx';
let boqMediaType = 'xlsx';
if (boqName.toLowerCase().endsWith('.pdf') || boq.mimeType === 'application/pdf') boqMediaType = 'pdf';

return [{
  json: {
    tenant_slug: TENANT_SLUG,
    backend_url: BACKEND_API_URL,
    credentials: JSON.stringify({ email: LOGIN_EMAIL, password: LOGIN_PASSWORD }),
    source_platform: 'email',
    platform_reply_info: JSON.stringify({ email: senderEmail, from_name: clean(data.client_name), smtp_from: 'Simplex Quotation Generator <rgmruh11@gmail.com>' }),
    client_data: JSON.stringify({
      name: clean(data.client_name),
      company_name: clean(data.company_name),
      email: clean(data.email) || senderEmail,
      phone: clean(data.phone) || null,
      address: clean(data.address) || null,
    }),
    project_data: JSON.stringify({
      project_name: clean(data.project_name),
      city: clean(data.city),
      country: clean(data.country),
      due_date: clean(data.due_date),
    }),
    quotation_config: JSON.stringify({
      service_option: serviceValue(data.service_option),
      margin_percent: Number(data.margin_percent || 0),
      payment_terms_text: clean(data.payment_terms_text) || null,
      subject: clean(data.subject) || null,
    }),
    boq_media_type: boqMediaType,
    callback_url: CALLBACK_ROUTER_URL,
  },
  binary: {
    boq_file: boq,
    spec_file: spec,
  },
}];

// Email platform upload path. Uses native HTTP for multipart because n8n's
// helper can corrupt binary multipart bodies in the Task Runner sandbox.
const http = require('http');
const https = require('https');

function parseUrl(s) {
  const m = String(s || '').match(/^(https?):\/\/([^\/:]+)(?::(\d+))?(\/.*)?$/);
  if (!m) return { protocol: 'http:', hostname: s, port: null, path: '/' };
  return { protocol: m[1] + ':', hostname: m[2], port: m[3] || null, path: m[4] || '/' };
}

function requestRaw(method, url, headers, body, timeoutMs = 120000) {
  return new Promise((resolve, reject) => {
    const parsed = parseUrl(url);
    const lib = parsed.protocol === 'https:' ? https : http;
    const req = lib.request({ hostname: parsed.hostname, port: parsed.port, path: parsed.path, method, headers }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        if (res.statusCode >= 400) return reject(new Error('HTTP ' + res.statusCode + ': ' + text));
        try { resolve(JSON.parse(text)); } catch (e) { resolve(text); }
      });
    });
    req.on('error', reject);
    req.setTimeout(timeoutMs, () => { req.destroy(); reject(new Error('HTTP timeout')); });
    if (body) req.write(body);
    req.end();
  });
}

const input = $input.first().json;
const binaryData = $input.first().binary || {};
const boqBinary = binaryData.boq_file;
const specBinary = binaryData.spec_file;
if (!boqBinary || !specBinary) throw new Error('Missing binary file inputs (boq_file, spec_file)');

const backendUrl = input.backend_url.replace(/\/$/, '');
const tenantSlug = input.tenant_slug;
const credentials = JSON.parse(input.credentials || '{}');

const loginBody = Buffer.from(JSON.stringify({ email: credentials.email, password: credentials.password }));
const loginResp = await requestRaw('POST', backendUrl + '/api/auth/login', {
  'Content-Type': 'application/json',
  'Content-Length': String(loginBody.length),
  'x-tenant-slug': tenantSlug,
}, loginBody, 30000);
if (!loginResp || !loginResp.access_token) throw new Error('Backend login failed');

const boundary = '----n8nEmail' + Date.now();
const CRLF = '\r\n';
function fieldPart(name, value) {
  return Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"' + CRLF + CRLF + String(value ?? '') + CRLF);
}
function filePart(name, filename, contentType, data) {
  return [
    Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"; filename="' + filename + '"' + CRLF + 'Content-Type: ' + contentType + CRLF + CRLF),
    data,
    Buffer.from(CRLF),
  ];
}

const parts = [];
parts.push(...filePart('boq_file', boqBinary.fileName || 'boq.xlsx', boqBinary.mimeType || 'application/octet-stream', Buffer.from(boqBinary.data, 'base64')));
parts.push(...filePart('spec_file', specBinary.fileName || 'specification.pdf', specBinary.mimeType || 'application/pdf', Buffer.from(specBinary.data, 'base64')));
parts.push(fieldPart('source_platform', input.source_platform || 'email'));
parts.push(fieldPart('platform_reply_info', input.platform_reply_info || '{}'));
parts.push(fieldPart('client_data', input.client_data || '{}'));
parts.push(fieldPart('project_data', input.project_data || '{}'));
parts.push(fieldPart('quotation_config', input.quotation_config || '{}'));
parts.push(fieldPart('boq_media_type', input.boq_media_type || 'xlsx'));
if (input.callback_url) parts.push(fieldPart('callback_url', input.callback_url));
parts.push(Buffer.from('--' + boundary + '--' + CRLF));
const body = Buffer.concat(parts);

const result = await requestRaw('POST', backendUrl + '/api/integrations/generic/quotation/start', {
  Authorization: 'Bearer ' + loginResp.access_token,
  'x-tenant-slug': tenantSlug,
  'Content-Type': 'multipart/form-data; boundary=' + boundary,
  'Content-Length': String(body.length),
}, body, 120000);

return [{ json: { status: result.status || 'started', project_id: result.project_id, pipeline_run_id: result.pipeline_run_id } }];
